Bash(node -e "
const responses = require\('./storage/responses/ai_sample_remote_work.json'\);
const form = require\('./storage/forms/ai_sample_remote_work.json'\);

// Compute stats like the API would
const stats = {};
form.questions.forEach\(q => {
  const answers = responses.map\(r => r.answers[q.id]\).filter\(a => a !== undefined && a !== null && a !== ''\);
  stats[q.id] = { total: answers.length };

  if \(['mcq','checkbox','dropdown','true_false'].includes\(q.type\)\) {
    const counts = {};
    answers.forEach\(a => {
      const vals = Array.isArray\(a\) ? a : [a];
      vals.forEach\(v => { if\(v\) counts[v] = \(counts[v]||0\)+1; }\);
    }\);
    stats[q.id].counts = counts;
  } else if \(q.type === 'rating'\) {
    const nums = answers.map\(Number\).filter\(n => !isNaN\(n\)\);
    const dist = {};
    nums.forEach\(n => { dist[n] = \(dist[n]||0\)+1; }\);
    stats[q.id].average = \(nums.reduce\(\(a,b\)=>a+b,0\)/nums.length\).toFixed\(1\);
    stats[q.id].distribution = dist;
  } else {
    stats[q.id].answers = answers;
  }
}\);

console.log\(JSON.stringify\({ total: 50, stats }, null, 2\)\);
" 2>&1 | head -200)
